#include <stdio.h>
#include <string.h>
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        char cake[N][M + 1];
        for (int i = 0; i < N; i++) {
            scanf("%s", cake[i]);
        }
        int cost1 = 0, cost2 = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if ((i + j) % 2 == 0) {
                    if (cake[i][j] != 'R') {
                        cost1 += 3;
                    }
                } else {
                    if (cake[i][j] != 'G') {
                        cost1 += 5;
                    }
                }
                if ((i + j) % 2 == 0) {
                    if (cake[i][j] != 'G') {
                        cost2 += 5;
                    }
                } else {
                    if (cake[i][j] != 'R') {
                        cost2 += 3;
                    }
                }
            }
        }
        printf("%d\n", cost1 < cost2 ? cost1 : cost2);
    }
    return 0;
}

