import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            String[] cake = new String[N];
            for (int i = 0; i < N; i++) {
                cake[i] = sc.next();
            }
            int cost1 = 0, cost2 = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if ((i + j) % 2 == 0) {
                        if (cake[i].charAt(j) != 'R') {
                            cost1 += 3;
                        }
                    } else {
                        if (cake[i].charAt(j) != 'G') {
                            cost1 += 5;
                        }
                    }
                    if ((i + j) % 2 == 0) {
                        if (cake[i].charAt(j) != 'G') {
                            cost2 += 5;
                        }
                    } else {
                        if (cake[i].charAt(j) != 'R') {
                            cost2 += 3;
                        }
                    }
                }
            }
            System.out.println(Math.min(cost1, cost2));
        }
    }
}

